import { FeedbackFlag } from '@/common/api/feedback';
import { SpaceTreeNodeType } from '@/types/space';

import { aioApi } from './api';

export interface IFeedbackItem {
  id: number;
  userId: string;
  userName: string;
  feedbackTime: string;
  docType: SpaceTreeNodeType | null;
  feedbackType: FeedbackFlag;
  relatedLink: string;
  content: string;
  attachments: string[];
  extraInfo: string | null;
  source: string | null;
  /** 0=未处理，1=已处理 */
  status: 0 | 1;
}

/**
 * 空间站管理后台
 * - Feedback
 *   - ${id}
 *   - List
 */
export const backendApi = aioApi.injectEndpoints({
  endpoints: (build) => ({
    getFeedbackList: build.query<{
      records: IFeedbackItem[];
      total: number;
      size: number;
      current: number;
      pages: number;
    }, {
      /** 反馈状态：0=未处理，1=已处理 */
      status?: 0 | 1;
      docType?: string;
      feedbackType?: FeedbackFlag;
      /** 格式 yyyy-MM-dd */
      startDate?: string;
      /** 格式 yyyy-MM-dd */
      endDate?: string;
      keyword?: string;
      pageNum?: number;
      pageSize?: number;
    }>({
      query: (data) => ({
        url: '/api/v1/feedback/list',

