import { SearchOutlined } from '@ant-design/icons';
import { useDebounceFn } from 'ahooks';
import {
  Button,
  DatePicker, Flex, Form, Input, Select, Table, TableColumnsType,
  Typography,
} from 'antd';
import type { Dayjs } from 'dayjs';
import { useEffect, useMemo, useState } from 'react';

import { FeedbackFlag } from '@/common/api/feedback';
import { feedbackTypeTextMap } from '@/components/FeedbackSubmission/FeedbackSubmission';
import { t } from '@/i18n';
import { useRootSelector } from '@/store';
import { IFeedbackItem, useGetFeedbackListQuery, useUpdateFeedbackStatusMutation } from '@/store/query/backend';
import { getEnv } from '@/store/system';
import { SpaceTreeNodeType, SpaceTreeNodeTypeText } from '@/types/space';
import { resolveRemoteAssetUrl } from '@/utils/upload';

const feedbackStatusOptions = [
  { label: t('finished'), value: 'finished' },
  { label: t('unfinished'), value: 'unfinished' },
  { label: t('all'), value: 'all' },
];

const feedbackDocTypeOptions = [
  ...Object.entries(SpaceTreeNodeTypeText)
    .filter(([type]) => ![SpaceTreeNodeType.Folder, SpaceTreeNodeType.Link, SpaceTreeNodeType.Luckysheet].includes(+type))
    .map(([type, text]) => ({ label: text, value: type })),
  { label: t('notDocPage'), value: '0' },
];

const feedbackTypeOptions = Object.entries(feedbackTypeTextMap).map(([type, text]) => ({ label: text, value: type as FeedbackFlag }));

type IFilterValues = {
  status?: 'finished' | 'unfinished' | 'all';
  docType?: string;
  type?: FeedbackFlag;
  timeRange?: [Dayjs, Dayjs] | null;
  keyword?: string;
};

type IQueryValues = {
  pageNum: number;
  pageSize: number;
};

export const AdminFeedback = () => {
  const env = useRootSelector(getEnv);
  const [query, setQuery] = useState<IQueryValues>({ pageNum: 1, pageSize: 20 });
  const [filter, setFilter] = useState<IFilterValues>({});

  const [updateFeedbackStatus] = useUpdateFeedbackStatusMutation();
  const { data, isFetching } = useGetFeedbackListQuery({
    ...query,
    status: filter.status === 'finished' ? 1 : filter.status === 'unfinished' ? 0 : undefined,
    docType: filter.docType,
    feedbackType: filter.type,
    startDate: filter.timeRange?.[0]?.format('YYYY-MM-DD'),
    endDate: filter.timeRange?.[1]?.format('YYYY-MM-DD'),
    keyword: filter.keyword,
  });

  const columns = useMemo<TableColumnsType<IFeedbackItem>>(() => [
    {
      title: `${t('feedbackProvider')} (user id)`,
      width: 200,
      render: (_, record) => `${record.userName} (${record.userId})`,
    },
    {
      title: t('feedbackTime'),
      width: 112,
      dataIndex: 'feedbackTime',
    },
    {
      title: t('docType'),
      width: 120,
      render: (_, record) => {
        if (!record.docType) return t('notDocPage');
        return SpaceTreeNodeTypeText[record.docType] ?? t('notDocPage');
      },
    },
    {
      title: t('feedbackType'),
      width: 100,
      render: (_, record) => feedbackTypeTextMap[record.feedbackType],
    },
    {
      title: t('relatedLinks'),
      width: 200,
      className: 'break-all',
      render: (_, record) => record.relatedLink,
    },
    {
      title: t('feedbackContent'),
      width: 200,
      dataIndex: 'content',
      render: (text) => (
        <Typography.Paragraph
          ellipsis={{
            expandable: 'collapsible',
            rows: 3,
          }}
          style={{ marginBottom: 0 }}
          title={text}
        >{text}
        </Typography.Paragraph>
      ),
    },
    {
      title: t('attachment'),
      width: 200,
      render: (_, record) => (
        <Flex wrap>{record.attachments.map((url, index) => (
          <Button
            key={index}
            type="link"
            size="small"
            onClick={() => window.open(resolveRemoteAssetUrl(env, url), '_blank')}
          >
            {t('attachment')} {index + 1}
          </Button>
        ))}
        </Flex>
      ),

    },
    {
      title: t('otherInformation'),
      width: 200,
      dataIndex: 'extraInfo',
    },
    {
      title: t('operations'),
      width: 140,
      render: (_, record) => (
        <Button
          type="link"
          size="small"
          onClick={() => updateFeedbackStatus({ feedbackId: record.id, status: record.status === 0 ? 1 : 0 }).unwrap()}
          danger={record.status === 1}
        >
          {record.status === 0 ? t('markAsFinished') : t('markAsUnfinished')}
        </Button>
      ),
    },
  ], [env, updateFeedbackStatus]);

  const scrollX = useMemo(() => columns.reduce((sum, col) => sum + (col.width as number || 100), 0), [columns]);
  const [tableContainerHeight, setTableContainerHeight] = useState(0);
  const [tableContainer, setTableContainer] = useState<HTMLElement | null>(null);
  useEffect(() => {
    if (!tableContainer) return;
    const ro = new ResizeObserver(() => {
      setTableContainerHeight(Math.max(0, tableContainer.clientHeight - 119)); // header 55 + pagination 64
    });
    ro.observe(tableContainer);
    return () => {
      ro.disconnect();
    };
  }, [tableContainer]);

  const { run: handleFilterChange } = useDebounceFn((values?: IFilterValues) => {
    setFilter(values ?? {});
    setQuery((q) => ({ ...q, pageNum: 1 }));
  }, { wait: 500 });

  return (
    <div className="h-full grid grid-rows-[auto_1fr] pr-4">
      <Form
        layout="inline"
        className="gap-2 mb-4"
        onValuesChange={(_, values: IFilterValues) => {
          handleFilterChange(values);
        }}
      >
        <Form.Item label={t('filter')} name="status" className="w-50">
          <Select options={feedbackStatusOptions} placeholder={t('feedbackStatusSelectPlaceholder')} />
        </Form.Item>
        <Form.Item name="docType" className="w-50">
          <Select
            allowClear
            options={feedbackDocTypeOptions}
            placeholder={t('feedbackDocTypeSelectPlaceholder')}
          />
        </Form.Item>
        <Form.Item name="type" className="w-50">
          <Select
            allowClear
            options={feedbackTypeOptions}
            placeholder={t('feedbackTypeSelectPlaceholder')}
          />
        </Form.Item>
        <Form.Item name="timeRange" className="w-60">
          <DatePicker.RangePicker />
        </Form.Item>
        <Form.Item name="keyword" label={t('searchInFilterResult')}>
          <Input prefix={<SearchOutlined />} placeholder={t('searchContent')} />
        </Form.Item>
      </Form>
      <main className="overflow-hidden" ref={setTableContainer}>
        <Table
          dataSource={data?.records}
          rowKey="id"
          columns={columns}
          loading={isFetching}
          scroll={{ x: scrollX, y: tableContainerHeight }}
          pagination={{
            current: query.pageNum,
            pageSize: query.pageSize,
            total: data?.total,
            onChange: (page, pageSize) => setQuery({ pageNum: page, pageSize }),
          }}
        />
      </main>
    </div>
  );
};

