 92→    @Override
 93→    public void mmWebhookFeedback(MmFeedbackWebhookRo ro) {
 94→        String action = StrUtil.blankToDefault(ro.getAction(), "create");
 95→        log.info("[lbl][2087-消息推送][Feedback][{}] MM消息同步, postId={}, nickName={}, messageId={}, fileCount={}",
 96→                action.toUpperCase(), ro.getPostId(), ro.getFeedbackNickName(), ro.getMessageId(),
 97→                ro.getFiles() != null ? ro.getFiles().size() : 0);
 98→
 99→        switch (action) {
100→            case "create" -> mmHandleCreate(ro);
101→            case "update" -> mmHandleUpdate(ro);
102→            case "delete" -> mmHandleDelete(ro);
103→            default -> log.warn("[lbl][2087-消息推送][Feedback] 未知action={}, postId={}", action, ro.getPostId());
104→        }
105→    }
106→
107→    private void mmHandleCreate(MmFeedbackWebhookRo ro) {
108→        List<String> attachmentUrls = downloadMmFiles(ro);
109→        LocalDateTime feedbackTime = parseFeedbackTime(ro.getFeedbackTime());
110→        String extraInfo = buildExtraInfo(ro.getMessageId());
111→
112→        FeedbackEntity entity = FeedbackEntity.builder()
113→                .postId(ro.getPostId())
114→                .userId(ro.getFeedbackNickName())
115→                .userName(ro.getFeedbackNickName())
116→                .feedbackTime(feedbackTime)
117→                .content(ro.getContent())
118→                .attachments(attachmentUrls.isEmpty() ? null : JSONUtil.toJsonStr(attachmentUrls))
119→                .extraInfo(extraInfo)
120→                .source(FeedbackSource.MM.getCode())
121→                .status(FeedbackStatus.UNPROCESSED.getCode())
122→                .build();
123→
124→        feedbackMapper.insert(entity);
125→        log.info("[lbl][2087-消息推送][Feedback][CREATE] 写入成功, id={}, postId={}, nickName={}",
126→                entity.getId(), ro.getPostId(), ro.getFeedbackNickName());
127→    }
128→
129→    private void mmHandleUpdate(MmFeedbackWebhookRo ro) {
130→        FeedbackEntity existing = findByPostId(ro.getPostId());
131→        if (existing == null) {
132→            log.warn("[lbl][2087-消息推送][Feedback][UPDATE] postId={} 记录不存在, 降级为create", ro.getPostId());
133→            mmHandleCreate(ro);
134→            return;
135→        }
136→
137→        List<String> attachmentUrls = downloadMmFiles(ro);
138→        existing.setContent(ro.getContent());
139→        existing.setAttachments(attachmentUrls.isEmpty() ? null : JSONUtil.toJsonStr(attachmentUrls));
140→        existing.setFeedbackTime(parseFeedbackTime(ro.getFeedbackTime()));
141→        existing.setExtraInfo(buildExtraInfo(ro.getMessageId()));
142→        feedbackMapper.updateById(existing);
143→        log.info("[lbl][2087-消息推送][Feedback][UPDATE] 更新成功, id={}, postId={}", existing.getId(), ro.getPostId());
144→    }
145→
146→    private void mmHandleDelete(MmFeedbackWebhookRo ro) {
147→        FeedbackEntity existing = findByPostId(ro.getPostId());
148→        if (existing == null) {
149→            log.warn("[lbl][2087-消息推送][Feedback][DELETE] postId={} 记录不存在, 忽略", ro.getPostId());
150→            return;
151→        }
152→
153→        existing.setIsDeleted(1);
154→        feedbackMapper.updateById(existing);
155→        log.info("[lbl][2087-消息推送][Feedback][DELETE] 逻辑删除成功, id={}, postId={}", existing.getId(), ro.getPostId());
156→    }
