170→    private List<String> downloadMmFiles(MmFeedbackWebhookRo ro) {
171→        List<String> fileIds = ro.getFiles() != null
172→                ? ro.getFiles().stream().map(MmFeedbackWebhookRo.MmFileInfo::getFileId).toList()
173→                : List.of();
174→        return downloadMmFilesAndUpload(fileIds);
175→    }
