188→    private String buildExtraInfo(String messageId) {
189→        return StrUtil.isNotBlank(messageId)
190→                ? JSONUtil.toJsonStr(cn.hutool.core.map.MapUtil.of("messageId", messageId))
191→                : null;
192→    }
