194→    @Override
195→    public IPage<FeedbackVo> listFeedback(FeedbackListRo ro) {
196→        int pageNum = ro.getPageNum() != null ? ro.getPageNum() : 1;
197→        int pageSize = ro.getPageSize() != null ? ro.getPageSize() : 20;
198→
199→        LambdaQueryWrapper<FeedbackEntity> wrapper = new LambdaQueryWrapper<>();
200→        wrapper.eq(FeedbackEntity::getIsDeleted, 0);
201→
202→        if (ro.getStatus() != null) {
203→            wrapper.eq(FeedbackEntity::getStatus, ro.getStatus());
204→        }
205→        if (StrUtil.isNotBlank(ro.getDocType())) {
206→            wrapper.eq(FeedbackEntity::getDocType, ro.getDocType());
207→        }
208→        if (StrUtil.isNotBlank(ro.getFeedbackType())) {
209→            wrapper.eq(FeedbackEntity::getFeedbackType, ro.getFeedbackType());
210→        }
211→        if (StrUtil.isNotBlank(ro.getStartDate())) {
212→            try {
213→                LocalDate startDate = LocalDate.parse(ro.getStartDate(), DateTimeFormatter.ISO_LOCAL_DATE);
214→                wrapper.ge(FeedbackEntity::getFeedbackTime, startDate.atStartOfDay());
215→            } catch (java.time.format.DateTimeParseException e) {
216→                throw new BusinessException("开始日期格式错误，应为yyyy-MM-dd");
217→            }
218→        }
219→        if (StrUtil.isNotBlank(ro.getEndDate())) {
220→            try {
221→                LocalDate endDate = LocalDate.parse(ro.getEndDate(), DateTimeFormatter.ISO_LOCAL_DATE);
222→                wrapper.le(FeedbackEntity::getFeedbackTime, endDate.plusDays(1).atStartOfDay());
223→            } catch (java.time.format.DateTimeParseException e) {
224→                throw new BusinessException("结束日期格式错误，应为yyyy-MM-dd");
225→            }
226→        }
227→        if (StrUtil.isNotBlank(ro.getKeyword())) {
228→            wrapper.like(FeedbackEntity::getContent, ro.getKeyword());
229→        }
230→
231→        wrapper.orderByDesc(FeedbackEntity::getFeedbackTime);
232→
233→        IPage<FeedbackEntity> page = feedbackMapper.selectPage(new Page<>(pageNum, pageSize), wrapper);
234→
235→        return page.convert(this::toVo);
236→    }
