238→    @Override
239→    public void updateFeedbackStatus(FeedbackUpdateStatusRo ro) {
240→        log.info("[lbl][2087-消息推送][Feedback][UPDATE] 更新反馈状态, id={}, status={}", ro.getFeedbackId(), ro.getStatus());
241→        FeedbackEntity entity = feedbackMapper.selectById(ro.getFeedbackId());
242→        if (entity == null) {
243→            log.warn("[lbl][2087-消息推送][Feedback][UPDATE] 反馈记录不存在, id={}", ro.getFeedbackId());
244→            throw new BusinessException("反馈记录不存在");
245→        }
246→        entity.setStatus(ro.getStatus());
247→        feedbackMapper.updateById(entity);
248→        log.info("[lbl][2087-消息推送][Feedback][UPDATE] 更新反馈状态成功, id={}, status={}", ro.getFeedbackId(), ro.getStatus());
249→    }
250→
251→    /**
252→     * 上传前端附件到MinIO
253→     */
254→    private List<String> uploadFilesToMinio(List<MultipartFile> files) {
255→        List<String> urls = new ArrayList<>();
256→        if (files == null || files.isEmpty()) {
257→            return urls;
258→        }
259→        String bucketName = constProperties.getOssBucketByAsset().getBucketName();
260→        for (MultipartFile file : files) {
261→            try {
262→                String keyPath = "feedback/" + LocalDate.now().format(DateTimeFormatter.BASIC_ISO_DATE)
263→                        + "/" + UUID.randomUUID() + "_" + file.getOriginalFilename();
264→                ossTemplate.upload(bucketName, file.getInputStream(), keyPath);
265→                String url = constProperties.getOssBucketByAsset().getResourceUrl() + "/" + keyPath;
266→                urls.add(url);
267→            } catch (IOException e) {
268→                log.error("[lbl][2087-消息推送][Feedback][UPLOAD] 附件上传MinIO失败, fileName={}, error={}", file.getOriginalFilename(), e.getMessage(), e);
269→            }
270→        }
271→        return urls;
272→    }
273→
274→    /**
275→     * 从MM下载附件并上传到MinIO
276→     */
277→    private List<String> downloadMmFilesAndUpload(List<String> fileIds) {
278→        List<String> urls = new ArrayList<>();
279→        if (fileIds == null || fileIds.isEmpty()) {
280→            return urls;
281→        }
282→        String bucketName = constProperties.getOssBucketByAsset().getBucketName();
283→        String authToken = "Bearer " + mattermostProperties.getXcollabspaceBotToken();
284→
285→        for (String fileId : fileIds) {
286→            try {
287→                log.info("[lbl][2087-消息推送][Feedback][DOWNLOAD] 调用MM Feign下载附件, fileId={}", fileId);
288→                byte[] fileData = mattermostMessageFeign.downloadFile(authToken, fileId);
289→                log.info("[lbl][2087-消息推送][Feedback][DOWNLOAD] MM附件下载完成, fileId={}, fileSize={}bytes", fileId, fileData.length);
290→                String keyPath = "feedback/mm/" + LocalDate.now().format(DateTimeFormatter.BASIC_ISO_DATE)
291→                        + "/" + UUID.randomUUID() + "_" + fileId;
292→                ossTemplate.upload(bucketName, new ByteArrayInputStream(fileData), keyPath);
293→                String url = constProperties.getOssBucketByAsset().getResourceUrl() + "/" + keyPath;
294→                urls.add(url);
295→                log.info("[lbl][2087-消息推送][Feedback][UPLOAD] MM附件上传MinIO成功, fileId={}, keyPath={}", fileId, keyPath);
296→            } catch (Exception e) {
297→                log.error("[lbl][2087-消息推送][Feedback][UPLOAD] MM附件下载上传失败, fileId={}, error={}", fileId, e.getMessage(), e);
298→            }
299→        }
300→        return urls;
301→    }
302→
303→    private FeedbackVo toVo(FeedbackEntity entity) {
304→        FeedbackVo vo = new FeedbackVo();
305→        vo.setId(entity.getId());
306→        vo.setUserId(entity.getUserId());
307→        vo.setUserName(entity.getUserName());
308→        vo.setFeedbackTime(entity.getFeedbackTime());
309→        vo.setDocType(entity.getDocType());
310→        vo.setFeedbackType(entity.getFeedbackType());
311→        vo.setRelatedLink(entity.getRelatedLink());
