313→        vo.setAttachments(StrUtil.isNotBlank(entity.getAttachments())
314→                ? JSONUtil.toList(entity.getAttachments(), String.class)
315→                : List.of());
316→        vo.setExtraInfo(entity.getExtraInfo());
317→        vo.setSource(entity.getSource());
318→        vo.setStatus(entity.getStatus());
319→        return vo;
320→    }
321→}
