@NoArgsConstructor
@AllArgsConstructor
@Accessors(chain = true)
@SuperBuilder
@TableName(keepGlobalPrefix = true, value = "feedback", autoResultMap = true)
public class FeedbackEntity extends BaseEntity implements Serializable {

    @Serial
    private static final long serialVersionUID = 1L;

    /** Mattermost消息ID，用于关联同一条消息的增/改/删 */
