package com.yottastudios.ns.collabspace.feedback.enums;

import lombok.AllArgsConstructor;
import lombok.Getter;

import java.util.Map;
import java.util.function.Function;
import java.util.stream.Collectors;
import java.util.stream.Stream;

@Getter
@AllArgsConstructor
public enum FeedbackType {
    LAG("lag", "卡顿"),
    BUG("bug", "Bug"),
    FEAT("feat", "功能建议"),
    OTHER("other", "其他");

    private final String code;
    private final String desc;

    private static final Map<String, FeedbackType> CODE_MAP = Stream.of(values())
            .collect(Collectors.toMap(FeedbackType::getCode, Function.identity()));

    public static String getDescByCode(String code) {
        FeedbackType type = CODE_MAP.get(code);
        return type != null ? type.getDesc() : code;
    }
}

