export const enum SpaceTreeNodeType {
  /** 文件夹 */
  Folder = 1,
  /** apitable 智能表格 */
  ApitableDst = 2,
  /** apitable 神奇表单 */
  ApitableForm = 3,
  /** apitable 仪表盘 */
  Dashboard = 4,
  /** apitable 镜像 */
  Mirror = 5,
  /** luckysheet表格 */
  Luckysheet = 6,
  /** affine 文档 */
  Affine = 7,
  /** outline文档 */
  Outline = 8,
  // onlyoffice 表格
  OnlyOfficeExcel = 9,
  /** 链接 */
  Link = 10,
  // onlyoffice 文档
  OnlyOfficeWord = 11,
  // onlyoffice 演示文稿
  OnlyOfficePpt = 12,
  /** 云盘文件 */
  NextCloud = 13,
}

/** 判断是否属于 OnlyOffice 节点 */
export function isOnlyOfficeNode(type: SpaceTreeNodeType) {
  return type === SpaceTreeNodeType.OnlyOfficeExcel
    || type === SpaceTreeNodeType.OnlyOfficeWord
    || type === SpaceTreeNodeType.OnlyOfficePpt;
}

export const SpaceTreeNodeTypeText: Record<SpaceTreeNodeType, string> = {
  [SpaceTreeNodeType.Folder]: t('folder'),
  [SpaceTreeNodeType.ApitableDst]: t('apitableDatasheet'),
  [SpaceTreeNodeType.ApitableForm]: t('apitableForm'),
  [SpaceTreeNodeType.Dashboard]: t('dashboard'),
  [SpaceTreeNodeType.Mirror]: t('mirror'),
  [SpaceTreeNodeType.Luckysheet]: t('luckysheet'),
  [SpaceTreeNodeType.OnlyOfficeExcel]: t('luckysheet'),
  [SpaceTreeNodeType.OnlyOfficeWord]: t('wordFile'),
  [SpaceTreeNodeType.OnlyOfficePpt]: t('pptFile'),
  [SpaceTreeNodeType.Affine]: t('affine'),
  [SpaceTreeNodeType.Outline]: 'Outline',
  [SpaceTreeNodeType.Link]: t('customLink'),
  [SpaceTreeNodeType.NextCloud]: t('nextCloudFile'),
};

export interface INodePermissions {
  allowEditConfigurable: boolean;
  allowSaveConfigurable: boolean;
  /** 是否能在此节点下创建文档, 根层级下是否有权限创建由后端判断 */
  childCreatable: boolean;
  copyable: boolean;
  descriptionEditable: boolean;
  editable: boolean;

