// docType 存储值 → 中文描述（数据库中存储的值比较混乱，尽力翻译）
private static final Map<String, String> DOC_TYPE_TEXT_MAP = Map.ofEntries(
        Map.entry("2", "智能表格"),
        Map.entry("3", "神奇表单"),
        Map.entry("4", "仪表盘"),
        Map.entry("5", "镜像"),
        Map.entry("6", "Luckysheet"),
        Map.entry("7", "Affine文档"),
        Map.entry("8", "Outline文档"),
        Map.entry("9", "表格"),
        Map.entry("11", "文档"),
        Map.entry("12", "演示文稿"),
        Map.entry("13", "云盘文件"),
        Map.entry("onlyoffice", "OnlyOffice")
);

private static final DateTimeFormatter CSV_TIME_FORMATTER = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
private static final String[] CSV_HEADERS = {"反馈人", "用户ID", "反馈时间", "文档类型", "反馈类型", "相关链接", "反馈内容", "附件", "其他信息", "来源", "处理状态"};

/**
 * 生成CSV字节数组（UTF-8 BOM，兼容Excel打开不乱码）
 */
private byte[] buildCsvBytes(List<FeedbackEntity> list) {
    StringBuilder sb = new StringBuilder();
    // UTF-8 BOM
    sb.append('\uFEFF');
    // 表头
    sb.append(String.join(",", CSV_HEADERS)).append("\r\n");
    // 数据行
    for (FeedbackEntity entity : list) {
        sb.append(escapeCsv(entity.getUserName())).append(',');
        sb.append(escapeCsv(entity.getUserId())).append(',');
        sb.append(escapeCsv(entity.getFeedbackTime() != null ? entity.getFeedbackTime().format(CSV_TIME_FORMATTER) : "")).append(',');
        sb.append(escapeCsv(translateDocType(entity.getDocType()))).append(',');
        sb.append(escapeCsv(FeedbackType.getDescByCode(entity.getFeedbackType()))).append(',');
        sb.append(escapeCsv(entity.getRelatedLink())).append(',');
        sb.append(escapeCsv(entity.getContent())).append(',');
        sb.append(escapeCsv(formatAttachments(entity.getAttachments()))).append(',');
        sb.append(escapeCsv(entity.getExtraInfo())).append(',');
        sb.append(escapeCsv(translateSource(entity.getSource()))).append(',');
        sb.append(escapeCsv(entity.getStatus() != null && entity.getStatus() == 1 ? "已处理" : "未处理"));
        sb.append("\r\n");
    }
    return sb.toString().getBytes(StandardCharsets.UTF_8);
}

/**
 * CSV字段转义：包含逗号、换行、双引号时，用双引号包裹
 */
private String escapeCsv(String value) {
    if (value == null) {
        return "";
    }
    if (value.contains(",") || value.contains("\"") || value.contains("\n") || value.contains("\r")) {
        return "\"" + value.replace("\"", "\"\"") + "\"";
    }
    return value;
}

private String translateDocType(String docType) {
    if (StrUtil.isBlank(docType)) {
        return "";
    }
    return DOC_TYPE_TEXT_MAP.getOrDefault(docType, docType);
}

private String translateSource(String source) {
    if (StrUtil.isBlank(source)) {
        return "";
    }
    for (FeedbackSource fs : FeedbackSource.values()) {
        if (fs.getCode().equals(source)) {
            return fs.getDesc();
        }
    }
    return source;
}

/**
 * JSON附件数组 → 换行分隔的URL字符串
 */
private String formatAttachments(String attachmentsJson) {
    if (StrUtil.isBlank(attachmentsJson)) {
        return "";
    }
    try {
        List<String> urls = JSONUtil.toList(attachmentsJson, String.class);
        return String.join("\n", urls);
    } catch (Exception e) {
        return attachmentsJson;
    }
}

