218→    /**
219→     * 构建查询条件（列表查询和导出共用）
220→     */
221→    private LambdaQueryWrapper<FeedbackEntity> buildQueryWrapper(FeedbackListRo ro) {
222→        LambdaQueryWrapper<FeedbackEntity> wrapper = new LambdaQueryWrapper<>();
223→        wrapper.eq(FeedbackEntity::getIsDeleted, 0);
224→
225→        if (ro.getStatus() != null) {
226→            wrapper.eq(FeedbackEntity::getStatus, ro.getStatus());
227→        }
228→        if (StrUtil.isNotBlank(ro.getDocType())) {
229→            wrapper.eq(FeedbackEntity::getDocType, ro.getDocType());
230→        }
231→        if (StrUtil.isNotBlank(ro.getFeedbackType())) {
232→            wrapper.eq(FeedbackEntity::getFeedbackType, ro.getFeedbackType());
233→        }
234→        if (StrUtil.isNotBlank(ro.getStartDate())) {
235→            try {
236→                LocalDate startDate = LocalDate.parse(ro.getStartDate(), DateTimeFormatter.ISO_LOCAL_DATE);
237→                wrapper.ge(FeedbackEntity::getFeedbackTime, startDate.atStartOfDay());
238→            } catch (java.time.format.DateTimeParseException e) {
239→                throw new BusinessException("开始日期格式错误，应为yyyy-MM-dd");
240→            }
241→        }
242→        if (StrUtil.isNotBlank(ro.getEndDate())) {
243→            try {
244→                LocalDate endDate = LocalDate.parse(ro.getEndDate(), DateTimeFormatter.ISO_LOCAL_DATE);
245→                wrapper.le(FeedbackEntity::getFeedbackTime, endDate.plusDays(1).atStartOfDay());
246→            } catch (java.time.format.DateTimeParseException e) {
247→                throw new BusinessException("结束日期格式错误，应为yyyy-MM-dd");
248→            }
249→        }
250→        if (StrUtil.isNotBlank(ro.getKeyword())) {
251→            wrapper.like(FeedbackEntity::getContent, ro.getKeyword());
252→        }
253→
254→        wrapper.orderByDesc(FeedbackEntity::getFeedbackTime);
255→        return wrapper;
256→    }
