277→    /**
278→     * 生成CSV字节数组（UTF-8 BOM，兼容Excel打开不乱码）
279→     */
280→    private byte[] buildCsvBytes(List<FeedbackEntity> list) {
281→        StringBuilder sb = new StringBuilder();
282→        // UTF-8 BOM
283→        sb.append('\uFEFF');
284→        // 表头
285→        sb.append(String.join(",", CSV_HEADERS)).append("\r\n");
286→        // 数据行
287→        for (FeedbackEntity entity : list) {
288→            sb.append(escapeCsv(entity.getUserName())).append(',');
289→            sb.append(escapeCsv(entity.getUserId())).append(',');
290→            sb.append(escapeCsv(entity.getFeedbackTime() != null ? entity.getFeedbackTime().format(CSV_TIME_FORMATTER) : "")).append(',');
291→            sb.append(escapeCsv(translateDocType(entity.getDocType()))).append(',');
292→            sb.append(escapeCsv(FeedbackType.getDescByCode(entity.getFeedbackType()))).append(',');
293→            sb.append(escapeCsv(entity.getRelatedLink())).append(',');
294→            sb.append(escapeCsv(entity.getContent())).append(',');
295→            sb.append(escapeCsv(formatAttachments(entity.getAttachments()))).append(',');
296→            sb.append(escapeCsv(entity.getExtraInfo())).append(',');
297→            sb.append(escapeCsv(translateSource(entity.getSource()))).append(',');
298→            sb.append(escapeCsv(entity.getStatus() != null && entity.getStatus() == 1 ? "已处理" : "未处理"));
299→            sb.append("\r\n");
300→        }
301→        return sb.toString().getBytes(StandardCharsets.UTF_8);
302→    }
303→
304→    /**
305→     * CSV字段转义：包含逗号、换行、双引号时，用双引号包裹
306→     */
307→    private String escapeCsv(String value) {
308→        if (value == null) {
309→            return "";
310→        }
311→        if (value.contains(",") || value.contains("\"") || value.contains("\n") || value.contains("\r")) {
312→            return "\"" + value.replace("\"", "\"\"") + "\"";
313→        }
314→        return value;
315→    }
316→
317→    private String translateDocType(String docType) {
318→        if (StrUtil.isBlank(docType)) {
319→            return "";
320→        }
321→        return DOC_TYPE_TEXT_MAP.getOrDefault(docType, docType);
322→    }
323→
324→    private String translateSource(String source) {
325→        if (StrUtil.isBlank(source)) {
326→            return "";
327→        }
328→        for (FeedbackSource fs : FeedbackSource.values()) {
329→            if (fs.getCode().equals(source)) {
330→                return fs.getDesc();
331→            }
332→        }
333→        return source;
334→    }
