336→    /**
337→     * JSON附件数组 → 换行分隔的URL字符串
338→     */
339→    private String formatAttachments(String attachmentsJson) {
340→        if (StrUtil.isBlank(attachmentsJson)) {
341→            return "";
342→        }
343→        try {
344→            List<String> urls = JSONUtil.toList(attachmentsJson, String.class);
345→            return String.join("\n", urls);
346→        } catch (Exception e) {
347→            return attachmentsJson;
348→        }
349→    }
