364→    /**
365→     * 上传前端附件到MinIO
366→     */
367→    private List<String> uploadFilesToMinio(List<MultipartFile> files) {
368→        List<String> urls = new ArrayList<>();
369→        if (files == null || files.isEmpty()) {
370→            return urls;
371→        }
372→        String bucketName = constProperties.getOssBucketByAsset().getBucketName();
373→        for (MultipartFile file : files) {
374→            try {
375→                String keyPath = "feedback/" + LocalDate.now().format(DateTimeFormatter.BASIC_ISO_DATE)
376→                        + "/" + UUID.randomUUID() + "_" + file.getOriginalFilename();
377→                ossTemplate.upload(bucketName, file.getInputStream(), keyPath);
378→                String url = constProperties.getOssBucketByAsset().getResourceUrl() + "/" + keyPath;
379→                urls.add(url);
380→            } catch (IOException e) {
381→                log.error("[lbl][2087-消息推送][Feedback][UPLOAD] 附件上传MinIO失败, fileName={}, error={}", file.getOriginalFilename(), e.getMessage(), e);
382→            }
383→        }
384→        return urls;
385→    }
