387→    /**
388→     * 从MM下载附件并上传到MinIO
389→     */
390→    private List<String> downloadMmFilesAndUpload(List<String> fileIds) {
391→        List<String> urls = new ArrayList<>();
392→        if (fileIds == null || fileIds.isEmpty()) {
393→            return urls;
394→        }
395→        String bucketName = constProperties.getOssBucketByAsset().getBucketName();
396→        String authToken = "Bearer " + mattermostProperties.getXcollabspaceBotToken();
397→
398→        for (String fileId : fileIds) {
399→            try {
