27→    public static void exportBytes(byte[] bytes, String filename, String contentType)
28→        throws IOException {
29→        HttpServletResponse response = HttpContextUtil.getResponse();
30→        OutputStream out = null;
31→        try {
32→            if (response != null) {
33→                if (contentType != null) {
34→                    response.setContentType(contentType);
35→                }
36→                response.setHeader("content-disposition", "attachment;filename=" + filename);
37→                out = response.getOutputStream();
38→                out.write(bytes);
39→            }
40→        } catch (Exception e) {
41→            // ignore
42→        } finally {
43→            if (out != null) {
44→                out.close();
45→            }
46→        }
47→    }
48→}
