 88→    /**
 89→     * customizer sql injector.
 90→     *
 91→     * @return sql injector
 92→     */
 93→    @Bean
 94→    public DefaultSqlInjector expandSqlInjector() {
 95→        // Support batch insertion
 96→        return new DefaultSqlInjector() {
 97→            @Override
 98→            public List<AbstractMethod> getMethodList(Class<?> mapperClass, TableInfo tableInfo) {
 99→                List<AbstractMethod> methodList = super.getMethodList(mapperClass, tableInfo);
100→                InsertBatchSomeColumn insertBatchSomeColumn = new InsertBatchSomeColumn(
101→                    t -> !StrUtil.equalsAny(t.getProperty(), "createdAt", "updatedAt",
102→                        "isDeleted"));
103→                methodList.add(insertBatchSomeColumn);
104→                return methodList;
105→            }
106→        };
107→    }
108→}
