/**
 * [反馈收集导出CSV] - 接口测试脚本
 *
 * 用法: node 05-test-api.js
 * 要求: Node.js 18+（原生 fetch）
 * 自动登录测试环境，无需手动填 Cookie
 */

// ========== 配置 ==========
const CONFIG = {
  host: 'http://xcollabspace-test.xtool-staging.yottastudios.com',
  loginEmail: 'luobeilin@yottastudios.com',
};

// ========== 测试框架 ==========
let passed = 0;
let failed = 0;
let cookie = '';
let xsrfToken = '';

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  ✅ ${name}`);
    passed++;
  } else {
    console.log(`  ❌ ${name}`);
    if (detail !== undefined)
      console.log(`     实际值:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== HTTP 工具 ==========

function parseCookies(res) {
  const cookies = {};
  const setCookieHeaders = res.headers.getSetCookie?.() || [];
  for (const header of setCookieHeaders) {
    const [kv] = header.split(';');
    const [k, v] = kv.split('=');
    cookies[k.trim()] = v.trim();
  }
  return cookies;
}

async function rawFetch(method, url, body) {
  const headers = {
    'content-type': 'application/json',
  };
  if (cookie) headers['cookie'] = cookie;
  if (xsrfToken) headers['x-xsrf-token'] = xsrfToken;

  const opts = { method, headers, redirect: 'manual' };
  if (body) opts.body = JSON.stringify(body);
  return fetch(url, opts);
}

/** GET 返回原始 Response（用于文件下载测试） */
async function GET_RAW(path) {
  return rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
}

/** GET 返回 JSON */
async function GET(path) {
  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
  return res.json();
}

// ========== 登录管理 ==========

async function login() {
  console.log(`🔑 登录 ${CONFIG.loginEmail} ...`);
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${CONFIG.loginEmail}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  if (!cookies.SESSION) {
    console.log('❌ 登录失败');
    process.exit(1);
  }
  xsrfToken = cookies['XSRF-TOKEN'] || '';
  cookie = `SESSION=${cookies.SESSION}; XSRF-TOKEN=${xsrfToken}`;
  console.log(`   ✅ 登录成功\n`);
}

let savedSessions = {};
function saveSession(name) {
  savedSessions[name] = { cookie, xsrfToken };
}
function restoreSession(name) {
  ({ cookie, xsrfToken } = savedSessions[name]);
}

async function loginAs(email) {
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${email}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  if (!cookies.SESSION) {
    console.log(`  ⚠️  登录 ${email} 失败，跳过`);
    return false;
  }
  xsrfToken = cookies['XSRF-TOKEN'] || '';
  cookie = `SESSION=${cookies.SESSION}; XSRF-TOKEN=${xsrfToken}`;
  return true;
}

// ========== 辅助：解析 CSV ==========

/** 解析 CSV 内容，返回 { headers: string[], rows: string[][] } */
function parseCsv(text) {
  // 去掉 BOM
  const clean = text.replace(/^\uFEFF/, '');
  const lines = clean.split('\r\n').filter(l => l.length > 0);
  if (lines.length === 0) return { headers: [], rows: [] };
  const headers = lines[0].split(',');
  const rows = lines.slice(1).map(l => l.split(','));
  return { headers, rows };
}

// ========== 测试用例 ==========

async function test_§1_正常导出() {
  console.log('📋 §1. 正常导出CSV');

  const res = await GET_RAW('/feedback/export');
  assert('§1.正常导出 - HTTP状态码200', res.status === 200, res.status);
  assert('§1.正常导出 - Content-Type为text/csv', res.headers.get('content-type')?.includes('text/csv'), res.headers.get('content-type'));
  assert('§1.正常导出 - Content-Disposition包含attachment', res.headers.get('content-disposition')?.includes('attachment'), res.headers.get('content-disposition'));
  assert('§1.正常导出 - 文件名包含.csv', res.headers.get('content-disposition')?.includes('.csv'), res.headers.get('content-disposition'));

  const text = await res.text();
  assert('§1.正常导出 - 响应体非空', text.length > 0, text.length);
  assert('§1.正常导出 - 包含UTF-8 BOM', text.charCodeAt(0) === 0xFEFF, `charCode=${text.charCodeAt(0)}`);

  const { headers, rows } = parseCsv(text);
  assert('§1.正常导出 - 表头11列', headers.length === 11, headers);
  assert('§1.正常导出 - 表头第1列=反馈人', headers[0] === '反馈人', headers[0]);
  assert('§1.正常导出 - 表头第2列=用户ID', headers[1] === '用户ID', headers[1]);
  assert('§1.正常导出 - 表头第11列=处理状态', headers[10] === '处理状态', headers[10]);
  assert('§1.正常导出 - 数据行数>0', rows.length > 0, rows.length);
  console.log(`   ℹ️  共导出 ${rows.length} 行数据`);
}

async function test_§2_筛选导出_按状态() {
  console.log('\n📋 §2. 按状态筛选导出');

  // 导出已处理
  const res1 = await GET_RAW('/feedback/export?status=1');
  assert('§2.按状态筛选 - status=1 返回200', res1.status === 200);
  const text1 = await res1.text();
  const { rows: rows1 } = parseCsv(text1);

  // 导出未处理
  const res0 = await GET_RAW('/feedback/export?status=0');
  const text0 = await res0.text();
  const { rows: rows0 } = parseCsv(text0);

  // 全量导出
  const resAll = await GET_RAW('/feedback/export');
  const textAll = await resAll.text();
  const { rows: rowsAll } = parseCsv(textAll);

  assert('§2.按状态筛选 - 已处理行数≤全量', rows1.length <= rowsAll.length);
  assert('§2.按状态筛选 - 未处理行数≤全量', rows0.length <= rowsAll.length);
  assert('§2.按状态筛选 - 已处理+未处理=全量', rows1.length + rows0.length === rowsAll.length, `${rows1.length}+${rows0.length} vs ${rowsAll.length}`);
  assert('§2.按状态筛选 - 已处理记录状态列=已处理', rows1.length === 0 || rows1.every(r => r[10] === '已处理'), rows1[0]?.[10]);
  assert('§2.按状态筛选 - 未处理记录状态列=未处理', rows0.length === 0 || rows0.every(r => r[10] === '未处理'), rows0[0]?.[10]);
  console.log(`   ℹ️  已处理${rows1.length}条, 未处理${rows0.length}条, 全量${rowsAll.length}条`);
}

async function test_§3_筛选导出_按反馈类型() {
  console.log('\n📋 §3. 按反馈类型筛选导出');

  const types = ['bug', 'feat', 'lag', 'other'];
  for (const t of types) {
    const res = await GET_RAW(`/feedback/export?feedbackType=${t}`);
    assert(`§3.按反馈类型 - feedbackType=${t} 返回200`, res.status === 200);
    const text = await res.text();
    const { rows } = parseCsv(text);
    console.log(`   ℹ️  feedbackType=${t}: ${rows.length}条`);
  }
}

async function test_§4_筛选导出_按时间范围() {
  console.log('\n📋 §4. 按时间范围筛选导出');

  // 有数据的时间范围
  const res1 = await GET_RAW('/feedback/export?startDate=2026-04-01&endDate=2026-04-30');
  assert('§4.按时间范围 - 有效日期范围返回200', res1.status === 200);
  const text1 = await res1.text();
  const { rows: rows1 } = parseCsv(text1);
  assert('§4.按时间范围 - 有数据的范围有结果', rows1.length > 0, rows1.length);

  // 未来时间范围（应无数据）
  const res2 = await GET_RAW('/feedback/export?startDate=2099-01-01&endDate=2099-12-31');
  const text2 = await res2.text();
  const { rows: rows2 } = parseCsv(text2);
  assert('§4.按时间范围 - 未来日期范围无数据', rows2.length === 0, rows2.length);

  // 非法日期格式
  const res3 = await GET_RAW('/feedback/export?startDate=abc');
  assert('§4.按时间范围 - 非法日期不报500', res3.status !== 500, res3.status);
}

async function test_§5_筛选导出_按关键字() {
  console.log('\n📋 §5. 按关键字筛选导出');

  // 用已知存在的关键字
  const res1 = await GET_RAW(`/feedback/export?keyword=${encodeURIComponent('测试')}`);
  assert('§5.按关键字 - 中文关键字返回200', res1.status === 200);
  const text1 = await res1.text();
  const { rows: rows1 } = parseCsv(text1);
  assert('§5.按关键字 - 匹配"测试"有结果', rows1.length > 0, rows1.length);

  // 不存在的关键字
  const res2 = await GET_RAW(`/feedback/export?keyword=${encodeURIComponent('不存在的关键字xyzabc')}`);
  const text2 = await res2.text();
  const { rows: rows2 } = parseCsv(text2);
  assert('§5.按关键字 - 不存在关键字无数据', rows2.length === 0, rows2.length);

  // 空关键字等同不传
  const resAll = await GET_RAW('/feedback/export');
  const textAll = await resAll.text();
  const { rows: rowsAll } = parseCsv(textAll);
  const resEmpty = await GET_RAW('/feedback/export?keyword=');
  const textEmpty = await resEmpty.text();
  const { rows: rowsEmpty } = parseCsv(textEmpty);
  assert('§5.按关键字 - 空keyword等同不传', rowsEmpty.length === rowsAll.length);
}

async function test_§6_组合筛选() {
  console.log('\n📋 §6. 组合筛选导出');

  const res = await GET_RAW('/feedback/export?status=0&feedbackType=bug&startDate=2026-04-01&endDate=2026-04-30');
  assert('§6.组合筛选 - 多条件组合返回200', res.status === 200);
  const text = await res.text();
  const { rows } = parseCsv(text);
  assert('§6.组合筛选 - 组合结果≤单条件结果', rows.length >= 0);
  console.log(`   ℹ️  组合筛选结果: ${rows.length}条`);
}

async function test_§7_CSV格式正确性() {
  console.log('\n📋 §7. CSV格式正确性');

  const res = await GET_RAW('/feedback/export');
  const text = await res.text();
  const clean = text.replace(/^\uFEFF/, '');
  const lines = clean.split('\r\n').filter(l => l.length > 0);

  // 每行逗号数应一致（11列 = 10个逗号，但含引号包裹的字段需特殊处理）
  const headerCommas = (lines[0].match(/,/g) || []).length;
  assert('§7.CSV格式 - 表头有10个逗号(11列)', headerCommas === 10, headerCommas);
  assert('§7.CSV格式 - 行尾是CRLF', text.includes('\r\n'));

  // 验证来源列翻译
  const { rows } = parseCsv(text);
  const sources = [...new Set(rows.map(r => r[9]))];
  console.log(`   ℹ️  来源值: ${sources.join(', ')}`);
  assert('§7.CSV格式 - 来源列为中文描述', sources.every(s => !['sentry', 'mm'].includes(s)), sources);

  // 验证处理状态列翻译
  const statuses = [...new Set(rows.map(r => r[10]))];
  assert('§7.CSV格式 - 状态列为中文(已处理/未处理)', statuses.every(s => ['已处理', '未处理'].includes(s)), statuses);
}

async function test_§8_特殊字符与注入防护() {
  console.log('\n🛡️ §8. 特殊字符与注入防护');

  const specialChars = ['%', '_', '\'', '"', '\\', '<script>', '&&', '||'];
  for (const ch of specialChars) {
    const res = await GET_RAW(`/feedback/export?keyword=${encodeURIComponent(ch)}`);
    assert(`§8.特殊字符 "${ch}" 不报500`, res.status !== 500, res.status);
  }

  const injections = [
    "' OR 1=1 --",
    "1; DROP TABLE collabspace_feedback;",
    "' UNION SELECT * FROM collabspace_feedback --",
  ];
  for (const payload of injections) {
    const res = await GET_RAW(`/feedback/export?keyword=${encodeURIComponent(payload)}`);
    assert(`§8.注入 "${payload.slice(0, 30)}..." 不报500`, res.status !== 500, res.status);
  }

  // 超长字符串
  const longStr = 'a'.repeat(500);
  const resLong = await GET_RAW(`/feedback/export?keyword=${encodeURIComponent(longStr)}`);
  assert('§8.超长keyword不报500', resLong.status !== 500, resLong.status);
}

async function test_§9_参数校验() {
  console.log('\n🔒 §9. 参数校验');

  // status 非法值
  const r1 = await GET_RAW('/feedback/export?status=99');
  assert('§9.参数校验 - status=99不报500', r1.status !== 500, r1.status);

  // status 非数字
  const r2 = await GET_RAW('/feedback/export?status=abc');
  assert('§9.参数校验 - status=abc不报500', r2.status !== 500, r2.status);

  // feedbackType 非法值
  const r3 = await GET_RAW('/feedback/export?feedbackType=nonexistent');
  assert('§9.参数校验 - feedbackType非法值返回200(空结果)', r3.status === 200);
  const text3 = await r3.text();
  const { rows: rows3 } = parseCsv(text3);
  assert('§9.参数校验 - feedbackType非法值无数据行', rows3.length === 0, rows3.length);
}

async function test_§10_并发请求() {
  console.log('\n🔀 §10. 并发请求');

  const promises = Array.from({ length: 5 }, () =>
    GET_RAW('/feedback/export')
  );
  const results = await Promise.all(promises);
  const allOk = results.every(r => r.status === 200);
  assert('§10.并发 - 5个并发导出都返回200', allOk);

  // 验证并发结果一致性
  const texts = await Promise.all(results.map(r => r.text()));
  const allSame = texts.every(t => t.length === texts[0].length);
  assert('§10.并发 - 并发结果长度一致', allSame, texts.map(t => t.length));
}

async function test_§11_未登录访问() {
  console.log('\n🔒 §11. 未登录访问');
  saveSession('main');

  // 清除 session
  cookie = '';
  xsrfToken = '';

  const res = await GET_RAW('/feedback/export');
  // GET 接口未登录行为取决于框架配置
  assert('§11.未登录 - 不报500', res.status !== 500, res.status);

  restoreSession('main');
}

async function test_§12_与列表接口数据一致性() {
  console.log('\n🔄 §12. 与列表接口数据一致性');

  // 从列表接口获取 total
  const listRes = await GET('/feedback/list?pageNum=1&pageSize=1');
  const total = listRes?.data?.total;
  assert('§12.一致性 - 列表接口返回成功', listRes?.success === true);

  // 从导出获取行数
  const exportRes = await GET_RAW('/feedback/export');
  const text = await exportRes.text();
  const { rows } = parseCsv(text);

  assert('§12.一致性 - 导出行数与列表total一致', rows.length === total, `导出${rows.length}行 vs 列表total=${total}`);
}

async function test_§13_docType筛选() {
  console.log('\n📋 §13. docType筛选导出');

  // 用数据库中实际存在的 docType 值测试
  const docTypes = ['onlyoffice', '2', '9', '11'];
  for (const dt of docTypes) {
    const res = await GET_RAW(`/feedback/export?docType=${encodeURIComponent(dt)}`);
    assert(`§13.docType=${dt} - 返回200`, res.status === 200);
  }
}

// ========== 执行 ==========
async function main() {
  console.log('🚀 [反馈收集导出CSV] - 接口测试');
  console.log(`   目标: ${CONFIG.host}`);
  console.log('');
  console.log('📋 功能点覆盖清单：');
  console.log('  §1. 正常导出CSV（表头、BOM、Content-Type、数据行）');
  console.log('  §2. 按状态筛选导出');
  console.log('  §3. 按反馈类型筛选导出');
  console.log('  §4. 按时间范围筛选导出');
  console.log('  §5. 按关键字筛选导出');
  console.log('  §6. 组合筛选导出');
  console.log('  §7. CSV格式正确性（翻译、CRLF）');
  console.log('  §8. 特殊字符与注入防护');
  console.log('  §9. 参数校验');
  console.log('  §10. 并发请求');
  console.log('  §11. 未登录访问');
  console.log('  §12. 与列表接口数据一致性');
  console.log('  §13. docType筛选');
  console.log('');

  try {
    await login();
    saveSession('main');

    await test_§1_正常导出();
    await test_§2_筛选导出_按状态();
    await test_§3_筛选导出_按反馈类型();
    await test_§4_筛选导出_按时间范围();
    await test_§5_筛选导出_按关键字();
    await test_§6_组合筛选();
    await test_§7_CSV格式正确性();
    await test_§8_特殊字符与注入防护();
    await test_§9_参数校验();
    await test_§10_并发请求();
    await test_§11_未登录访问();
    await test_§12_与列表接口数据一致性();
    await test_§13_docType筛选();
  } catch (e) {
    if (e.cause?.code === 'ECONNREFUSED') {
      console.log('\n❌ 无法连接测试环境，请检查网络');
    } else {
      console.log(`\n❌ 异常: ${e.stack || e.message}`);
    }
    process.exit(1);
  }

  console.log(`\n=============================`);
  console.log(`✅ 通过: ${passed}  ❌ 失败: ${failed}  📊 总计: ${passed + failed}`);
  console.log(`=============================`);
  process.exit(failed > 0 ? 1 : 0);
}
main();

