109→/** 解析 CSV 内容，返回 { headers: string[], rows: string[][] } */
110→function parseCsv(text) {
111→  // 去掉 BOM
112→  const clean = text.replace(/^\uFEFF/, '');
113→  const lines = clean.split('\r\n').filter(l => l.length > 0);
114→  if (lines.length === 0) return { headers: [], rows: [] };
115→  const headers = lines[0].split(',');
116→  const rows = lines.slice(1).map(l => l.split(','));
117→  return { headers, rows };
118→}
