async function test_7_csv_format() {
  console.log('\n📋 §7. CSV格式正确性');

  const res = await GET_RAW('/feedback/export');
  const text = await res.text();
  const clean = text.replace(/^\uFEFF/, '');
  const lines = clean.split('\r\n').filter(l => l.length > 0);

  // 每行逗号数应一致（11列 = 10个逗号，但含引号包裹的字段需特殊处理）
  const headerCommas = (lines[0].match(/,/g) || []).length;
  assert('§7.CSV格式 - 表头有10个逗号(11列)', headerCommas === 10, headerCommas);
  assert('§7.CSV格式 - 行尾是CRLF', text.includes('\r\n'));

  // 验证来源列翻译
  const { rows } = parseCsv(text);
  const sources = [...new Set(rows.map(r => r[9]))];
  console.log(`   ℹ️  来源值: ${sources.join(', ')}`);
  assert('§7.CSV格式 - 来源列为中文描述', sources.every(s => !['sentry', 'mm'].includes(s)), sources);

  // 验证处理状态列翻译
  const statuses = [...new Set(rows.map(r => r[10]))];
  assert('§7.CSV格式 - 状态列为中文(已处理/未处理)', statuses.every(s => ['已处理', '未处理'].includes(s)), statuses);
}

async function test_8_injection() {
  console.log('\n🛡️ §8. 特殊字符与注入防护');

  const specialChars = ['%', '_', '\'', '"', '\\', '<script>', '&&', '||'];
  for (const ch of specialChars) {
    const res = await GET_RAW(`/feedback/export?keyword=${encodeURIComponent(ch)}`);
    assert(`§8.特殊字符 "${ch}" 不报500`, res.status !== 500, res.status);
  }

  const injections = [
    "' OR 1=1 --",
    "1; DROP TABLE collabspace_feedback;",
    "' UNION SELECT * FROM collabspace_feedback --",
  ];
  for (const payload of injections) {
    const res = await GET_RAW(`/feedback/export?keyword=${encodeURIComponent(payload)}`);
    assert(`§8.注入 "${payload.slice(0, 30)}..." 不报500`, res.status !== 500, res.status);
  }

  // 超长字符串
  const longStr = 'a'.repeat(500);
  const resLong = await GET_RAW(`/feedback/export?keyword=${encodeURIComponent(longStr)}`);
  assert('§8.超长keyword不报500', resLong.status !== 500, resLong.status);
}

async function test_9_param_validation() {
  console.log('\n🔒 §9. 参数校验');

  // status 非法值
  const r1 = await GET_RAW('/feedback/export?status=99');
  assert('§9.参数校验 - status=99不报500', r1.status !== 500, r1.status);

  // status 非数字
  const r2 = await GET_RAW('/feedback/export?status=abc');
  assert('§9.参数校验 - status=abc不报500', r2.status !== 500, r2.status);

  // feedbackType 非法值
  const r3 = await GET_RAW('/feedback/export?feedbackType=nonexistent');
  assert('§9.参数校验 - feedbackType非法值返回200(空结果)', r3.status === 200);
  const text3 = await r3.text();
  const { rows: rows3 } = parseCsv(text3);
  assert('§9.参数校验 - feedbackType非法值无数据行', rows3.length === 0, rows3.length);
}

async function test_§10_并发请求() {
  console.log('\n🔀 §10. 并发请求');

  const promises = Array.from({ length: 5 }, () =>
    GET_RAW('/feedback/export')
  );
  const results = await Promise.all(promises);
  const allOk = results.every(r => r.status === 200);
  assert('§10.并发 - 5个并发导出都返回200', allOk);

  // 验证并发结果一致性
  const texts = await Promise.all(results.map(r => r.text()));
  const allSame = texts.every(t => t.length === texts[0].length);
  assert('§10.并发 - 并发结果长度一致', allSame, texts.map(t => t.length));
}

async function test_§11_未登录访问() {
  console.log('\n🔒 §11. 未登录访问');
  saveSession('main');

  // 清除 session
  cookie = '';
  xsrfToken = '';

  const res = await GET_RAW('/feedback/export');
  // GET 接口未登录行为取决于框架配置
  assert('§11.未登录 - 不报500', res.status !== 500, res.status);

  restoreSession('main');
}

async function test_§12_与列表接口数据一致性() {
  console.log('\n🔄 §12. 与列表接口数据一致性');

  // 从列表接口获取 total
  const listRes = await GET('/feedback/list?pageNum=1&pageSize=1');
  const total = listRes?.data?.total;
  assert('§12.一致性 - 列表接口返回成功', listRes?.success === true);

  // 从导出获取行数
  const exportRes = await GET_RAW('/feedback/export');
  const text = await exportRes.text();
  const { rows } = parseCsv(text);

  assert('§12.一致性 - 导出行数与列表total一致', rows.length === total, `导出${rows.length}行 vs 列表total=${total}`);
}

async function test_§13_docType筛选() {
  console.log('\n📋 §13. docType筛选导出');

