 629→  // 2. 验证每个 unitId 都生效
 630→  const after = await GET('/listXxx?pageNo=1&pageSize=100');
 631→  const u1 = after.data?.records?.find(r => r.unitId === unitId1);
 632→  const u2 = after.data?.records?.find(r => r.unitId === unitId2);
 633→  assert('批量操作后 u1 角色正确', u1?.role === 'editor');
 634→  assert('批量操作后 u2 角色正确', u2?.role === 'editor');
 635→
 636→  // 3. batchDeleteRole
 637→  const batchDelRes = await POST('/batchDeleteRole', {
 638→    spaceNodeId: CONFIG.spaceNodeId,
 639→    unitIds: [unitId1],
 640→  });
 641→  assert('batchDeleteRole 返回 success', batchDelRes.success === true);
 642→
 643→  // 4. 还原
 644→}
 645→```
